use strict;
use warnings;

my %plugins;

sub load_plugins {
    my $dir = shift || '.';
    opendir(my $dh, $dir) or die "Can't open dir $dir: $!";
    while (my $file = readdir($dh)) {
        next if $file !~ /\.pm$/; # only load .pm files
        no strict 'refs';
        eval "require $file";
        my ($class) = $file =~ /(.*?)\\./;
        $plugins{$class} = 1;
    }
    closedir($dh);
}

sub run_plugin {
    my $code = shift;
    eval($code);
}

load_plugins(); # load plugins from current directory by default

while (my $line = <STDIN>) {
    chomp($line);
    if ($line =~ /^run ([A-Z_]+)$/) {
        my $class = $1;
        if (exists $plugins{$class}) {
            my $method = 'main'; # default method to call for the plugin
            no strict 'refs';
            run_plugin("$class->$method()");
        } else {
            print "No such plugin: $class\n";
        }
    } else {
        print "Invalid command. Use 'run [PluginName]' to execute a plugin.\n";
    }
}